#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <functional>

// Utility to capture stdout
std::string capture_stdout(std::function<void()> func) {
    std::stringstream ss;
    std::streambuf* old_cout = std::cout.rdbuf();
    std::cout.rdbuf(ss.rdbuf());
    func();
    std::cout.rdbuf(old_cout);
    return ss.str();
}

// Utility to feed stdin
void set_stdin(const std::string& input) {
    std::stringstream ss(input);
    std::cin.rdbuf(ss.rdbuf());
}

